二维数组与二维字符数组一、二维数组基础定义1. 定义格式int arr[2][3];

int：数组元素类型，单个int占4字节
arr：数组名
第一个[]：行数，本例行下标取值0、1，共2行
第二个[]：列数，本例列下标取值0、1、2，共3列
总元素数量 = 行数 × 列数，本数组总共有 2×3=6 个元素
未初始化时，数组内存储随机垃圾值

2. 内存存储本质二维数组在内存中是连续的一维空间，存储顺序先行后列：arr[0][0] → arr[0][1] → arr[0][2] → arr[1][0] → arr[1][1] → arr[1][2]
二、二维数组初始化四种合法写法
物理完全初始化（平铺全部数值）int arr[2][3] = &#123;1,2,3,4,5,6&#125;;
物理部分初始化（剩余元素自动补0）int arr[2][3] = &#123;1,2,3&#125;;
逻辑完全初始化（大括号分行，可读性高）int arr[2][3] = &#123;&#123;1,2,3&#125;,&#123;4,5,6&#125;&#125;;
逻辑部分初始化（空缺位置补0）int arr[2][3] = &#123;&#123;1,2&#125;,&#123;5,6&#125;&#125;;
错误写法不能混合平铺与分行大括号，如下代码编译报错：int arr[2][3] = &#123;1,&#123;2,4&#125;,5&#125;; // 非法


三、二维数组两种遍历方式方式1：二维思想（双层for循环，标准写法）按行、列下标依次访问，可打印每个元素内存地址#include &lt;stdio.h&gt;int main()&#123;    int arr[2][3] = &#123;1,2,3,4,5,6&#125;;    // i控制行，j控制列    for (int i = 0; i &lt; 2; i++)    &#123;        for (int j = 0; j &lt; 3; j++)        &#123;            printf(&quot;元素arr[%d][%d]地址：%p
&quot;,i,j,&amp;arr[i][j]);        &#125;    &#125;    return 0;&#125;
方式2：一维思想（把二维当成一维连续内存读取）利用内存连续性，单循环遍历所有元素，按列数换行#include &lt;stdio.h&gt;int main()&#123;    int arr[2][3] = &#123;1,2,3,4,5,6&#125;;    // 总元素6个，循环6次    for (int i = 0; i &lt; 6; i++)    &#123;        printf(&quot;%d &quot;,arr[0][i]);        // 每3个元素换行        if ((i + 1) % 3 == 0)        &#123;            printf(&quot;
&quot;);        &#125;    &#125;    return 0;&#125;
补充：下标越界示例（危险代码）数组下标无编译器检查，负数下标会访问非法内存，输出乱码#include &lt;stdio.h&gt;int main()&#123;    int arr[2][3] = &#123;1,2,3,4,5,6&#125;;    for (int i = -3; i &lt; 3; i++)    &#123;        printf(&quot;%d &quot;,arr[1][i]);        if ((i + 1) % 3 == 0)        &#123;            printf(&quot;
&quot;);        &#125;    &#125;    return 0;&#125;
四、动态输入数值型二维数组完整代码案例1：一维思路输入，二维格式输出（完整可运行）#include &lt;stdio.h&gt;#define MAX 6#define OVER -999int main()&#123;    int arr[MAX];    int count = 0;    // 循环录入数据    while (count &lt; MAX)    &#123;        printf(&quot;请输入第%d/%d个数：&quot;,count + 1, MAX);        int num;        // 输入容错，非数字清空缓冲区        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入有误，请重试:&quot;);            while (getchar() != &#x27;
&#x27;);        &#125;        // 输入终止值退出录入        if (num == OVER)        &#123;            break;        &#125;        arr[count++] = num;    &#125;    // 二维格式输出，每行3个，空位打印-    for (int i = 0; i &lt; MAX; i++)    &#123;        if (i &lt; count)        &#123;            printf(&quot;%d &quot;,arr[i]);        &#125;        else        &#123;            printf(&quot;- &quot;);        &#125;        if ((i + 1) % 3 == 0)        &#123;            printf(&quot;
&quot;);        &#125;    &#125;    return 0;&#125;
配套作业：在此代码基础上，新增继续输入功能
案例2：二维思路录入（完整可运行）#include &lt;stdio.h&gt;#define COWS 2  // 行数#define COLS 3  // 列数#define OVER -999int main()&#123;    int arr[COWS][COLS];    int count = 0;    while (count &lt; COWS * COLS)    &#123;        printf(&quot;请输入第%d/%d个数：&quot;,count + 1, COWS * COLS);        int num;        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入有误，请重试:&quot;);            while (getchar() != &#x27;
&#x27;);        &#125;        if (num == OVER) break;        // 计算当前行列下标        int cow = count / COLS;        int col = count % COLS;        arr[cow][col] = num;        count++;    &#125;    // 二维打印    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)            &#123;                printf(&quot;%d &quot;,arr[i][j]);            &#125;            else            &#123;                printf(&quot;- &quot;);            &#125;        &#125;        printf(&quot;
&quot;);    &#125;    return 0;&#125;
配套作业：在此代码基础上，实现继续输入功能
五、二维数组排序完整代码方案1：一维中转冒泡排序（完整代码）#include &lt;stdio.h&gt;#define COWS 2#define COLS 3#define OVER -999int main()&#123;    int arr[COWS][COLS];    int count = 0;    // 录入数据    while (count &lt; COWS * COLS)    &#123;        printf(&quot;请输入第%d/%d个数：&quot;,count + 1, COWS * COLS);        int num;        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入有误，请重试:&quot;);            while (getchar() != &#x27;
&#x27;);        &#125;        if (num == OVER) break;        int cow = count / COLS;        int col = count % COLS;        arr[cow][col] = num;        count++;    &#125;    // 排序前输出    printf(&quot;排序前数组：
&quot;);    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)                printf(&quot;%d &quot;,arr[i][j]);            else                printf(&quot;- &quot;);        &#125;        printf(&quot;
&quot;);    &#125;    // 拷贝到一维数组    int arr_1[COWS * COLS];    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)            &#123;                arr_1[i * COLS + j] = arr[i][j];            &#125;        &#125;    &#125;    // 冒泡排序一维数组    for (int i = 0; i &lt; count - 1; i++)    &#123;        for (int j = 0; j &lt; count - 1 - i; j++)        &#123;            if (arr_1[j] &gt; arr_1[j + 1])            &#123;                int tmp = arr_1[j];                arr_1[j] = arr_1[j + 1];                arr_1[j + 1] = tmp;            &#125;        &#125;    &#125;    // 排序后二维输出    printf(&quot;排序后数组：
&quot;);    for (int i = 0; i &lt; COWS * COLS; i++)    &#123;        if (i &lt; count)        &#123;            printf(&quot;%d &quot;,arr_1[i]);        &#125;        else        &#123;            printf(&quot;- &quot;);        &#125;        if ((i + 1) % COLS == 0)        &#123;            printf(&quot;
&quot;);        &#125;    &#125;    return 0;&#125;
方案2：二维直接冒泡排序（完整代码，仅替换排序部分）#include &lt;stdio.h&gt;#define COWS 2#define COLS 3#define OVER -999int main()&#123;    int arr[COWS][COLS];    int count = 0;    // 录入数据（和上方代码录入部分完全一致）    while (count &lt; COWS * COLS)    &#123;        printf(&quot;请输入第%d/%d个数：&quot;,count + 1, COWS * COLS);        int num;        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入有误，请重试:&quot;);            while (getchar() != &#x27;
&#x27;);        &#125;        if (num == OVER) break;        int cow = count / COLS;        int col = count % COLS;        arr[cow][col] = num;        count++;    &#125;    printf(&quot;排序前：
&quot;);    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)                printf(&quot;%d &quot;,arr[i][j]);            else                printf(&quot;- &quot;);        &#125;        printf(&quot;
&quot;);    &#125;    // 二维直接排序核心代码    for (int i = 0; i &lt; count - 1; i++)    &#123;        for (int j = 0; j &lt; count - 1 - i; j++)        &#123;            int cur_cow = j / COLS;            int cur_col = j % COLS;            int next_cow = (j + 1) / COLS;            int next_col = (j + 1) % COLS;            if (arr[cur_cow][cur_col] &gt; arr[next_cow][next_col])            &#123;                int tmp = arr[cur_cow][cur_col];                arr[cur_cow][cur_col] = arr[next_cow][next_col];                arr[next_cow][next_col] = tmp;            &#125;        &#125;    &#125;    // 排序后打印    printf(&quot;排序后：
&quot;);    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)                printf(&quot;%d &quot;,arr[i][j]);            else                printf(&quot;- &quot;);        &#125;        printf(&quot;
&quot;);    &#125;    return 0;&#125;
配套作业：编写代码输出二维数组最大值、最小值、所有元素总和
六、二维字符数组1. 基础定义与打印完整代码#include &lt;stdio.h&gt;int main()&#123;    // 3行科目，每行最多10字符    char sub[3][10] = &#123;&quot;语文&quot;,&quot;数学&quot;,&quot;英语&quot;&#125;;    for (int i = 0; i &lt; 3; i++)    &#123;        printf(&quot;%s
&quot;,sub[i]);    &#125;    return 0;&#125;
2. 二维字符数组输入案例：录入学生姓名（1）scanf版本（不安全，完整代码）#include &lt;stdio.h&gt;#include &lt;string.h&gt;#define COWS 5#define COLS 10int main()&#123;    char name[COWS][COLS];    int count = 0;    while (1)    &#123;        if (count &gt;= COWS)        &#123;            printf(&quot;数据库已满！&quot;);            return 1;        &#125;        char tmp[COLS];        printf(&quot;请输入第%d个学生的姓名：&quot;,count + 1);        scanf(&quot;%4s&quot;,tmp);        tmp[strcspn(tmp,&quot;
&quot;)] = &#x27;\0&#x27;;        if (!strcmp(tmp,&quot;exit&quot;))        &#123;            break;        &#125;        strcpy(name[count++],tmp);    &#125;    printf(&quot;已录入学生名单：
&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        printf(&quot;%s
&quot;,name[i]);    &#125;    return 0;&#125;
（2）fgets版本（安全推荐，完整代码）#include &lt;stdio.h&gt;#include &lt;string.h&gt;#define COWS 5#define COLS 10int main()&#123;    char name[COWS][COLS];    int count = 0;    while (1)    &#123;        if (count &gt;= COWS)        &#123;            printf(&quot;数据库已满！&quot;);            return 1;        &#125;        char tmp[COLS];        printf(&quot;请输入第%d个学生的姓名：&quot;,count + 1);        fgets(tmp,sizeof(tmp),stdin);        tmp[strcspn(tmp,&quot;
&quot;)] = &#x27;\0&#x27;;        if (!strcmp(tmp,&quot;exit&quot;))        &#123;            break;        &#125;        strcpy(name[count++],tmp);    &#125;    printf(&quot;已录入学生名单：
&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        printf(&quot;%s
&quot;,name[i]);    &#125;    return 0;&#125;
七、综合完整案例：学生成绩信息管理和统计系统（全文完整可运行）#include &lt;stdio.h&gt;#include &lt;string.h&gt;#define COWS 3    // 最多学生人数#define COLS 4    // 科目数量#define SUM_AVG 2 // 总分、平均分两列int main()&#123;    char name[COWS][20];    char sub[COLS][20] = &#123;&quot;语文&quot;,&quot;数学&quot;,&quot;英语&quot;,&quot;地理&quot;&#125;;    float score[COWS][COLS];    float sum_avg[COWS][SUM_AVG] = &#123;0.00&#125;;    int count = 0;    while (1)    &#123;        if (count &gt;= COWS)        &#123;            printf(&quot;数据库已满！
&quot;);            break;        &#125;        char tmp[20];        printf(&quot;请输入第%d个学生的姓名：&quot;,count + 1);        fgets(tmp,sizeof(tmp),stdin);        tmp[strcspn(tmp,&quot;
&quot;)] = &#x27;\0&#x27;;        if (!tmp[0])        &#123;            printf(&quot;姓名不能为空，请重新输入！
&quot;);            continue;        &#125;        if (!strcmp(tmp,&quot;exit&quot;))        &#123;            break;        &#125;        strcpy(name[count],tmp);        // 录入该学生各科成绩        for (int i = 0; i &lt; COLS; i++)        &#123;            printf(&quot;请输入%s的%s的成绩:&quot;,name[count],sub[i]);            float tmp_score;            while (1)            &#123;                while (!scanf(&quot;%f&quot;,&amp;tmp_score))                &#123;                    printf(&quot;输入有误，请重试：&quot;);                    while (getchar() != &#x27;
&#x27;);                &#125;                if (tmp_score &lt; 0 || tmp_score &gt; 100)                &#123;                    printf(&quot;成绩无效，请重新输入:&quot;);                    continue;                &#125;                break;            &#125;            score[count][i] = tmp_score;            sum_avg[count][0] += tmp_score;            getchar();        &#125;        sum_avg[count][1] = sum_avg[count][0] / COLS;        count++;    &#125;    // 打印学生总表    printf(&quot;
%-10s&quot;,&quot;姓名&quot;);    for (int i = 0; i &lt; COLS; i++)    &#123;        printf(&quot;%-12s&quot;,sub[i]);    &#125;    printf(&quot;%-12s%-12s
&quot;,&quot;总成绩&quot;,&quot;平均成绩&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        printf(&quot;%-10s&quot;,name[i]);        for (int j = 0; j &lt; COLS; j++)        &#123;            printf(&quot;%-12.2f&quot;,score[i][j]);        &#125;        printf(&quot;%-12.2f%-12.2f
&quot;,sum_avg[i][0],sum_avg[i][1]);    &#125;    // 科目统计模块    float sub_sum[COLS];    float sub_top[COLS];    float sub_low[COLS];    char sub_top_name[COLS][20];    char sub_low_name[COLS][20];    if (count &lt;= 0)    &#123;        printf(&quot;无数据！&quot;);        return 1;    &#125;    // 初始化每科数据    for (int i = 0; i &lt; COLS; i++)    &#123;        sub_sum[i] = 0;        sub_top[i] = score[0][i];        sub_low[i] = score[0][i];        strcpy(sub_top_name[i],name[0]);        strcpy(sub_low_name[i],name[0]);    &#125;    // 遍历所有学生统计各科    for (int i = 0; i &lt; COLS; i++)    &#123;        for (int j = 0 ; j &lt; count; j++)        &#123;            sub_sum[i] += score[j][i];            if (sub_top[i] &lt; score[j][i])            &#123;                sub_top[i] = score[j][i];                strcpy(sub_top_name[i],name[j]);            &#125;            if (sub_low[i] &gt; score[j][i])            &#123;                sub_low[i] = score[j][i];                strcpy(sub_low_name[i],name[j]);            &#125;        &#125;    &#125;    // 打印科目统计表格    printf(&quot;


&quot;);    printf(&quot;%-8s%-8s%-12s%-12s%-8s%-12s%-8s
&quot;,&quot;科目&quot;,    &quot;总分&quot;,&quot;平均分&quot;,&quot;最高分&quot;,&quot;姓名&quot;,&quot;最低分&quot;,&quot;姓名&quot;);    for (int i = 0; i &lt; COLS; i++)    &#123;        printf(&quot;%-8s%-8.2f%-12.2f%-12.2f%-8s%-12.2f%-8s
&quot;,sub[i]        ,sub_sum[i],sub_sum[i] / count,sub_top[i],sub_top_name[i]        ,sub_low[i],sub_low_name[i]);    &#125;    return 0;&#125;
