作业1：二维数组基础作业（求最大值、最小值、元素总和）需求动态录入二维数组，遍历有效元素，输出总和、最大值、最小值#include &lt;stdio.h&gt;#define COWS 2#define COLS 3#define OVER -999int main()&#123;    int arr[COWS][COLS];    int count = 0;    // 录入数据    while (count &lt; COWS * COLS)    &#123;        printf(&quot;请输入第%d/%d个数：&quot;, count + 1, COWS * COLS);        int num;        while (!scanf(&quot;%d&quot;, &amp;num))        &#123;            printf(&quot;输入有误，请重试：&quot;);            while (getchar() != &#x27;
&#x27;);        &#125;        if (num == OVER)            break;        int cow = count / COLS;        int col = count % COLS;        arr[cow][col] = num;        count++;    &#125;    // 输出原始数组    printf(&quot;当前二维数组：
&quot;);    for (int i = 0; i &lt; COWS; i++)    &#123;        for (int j = 0; j &lt; COLS; j++)        &#123;            if ((i * COLS + j) &lt; count)                printf(&quot;%d &quot;, arr[i][j]);            else                printf(&quot;- &quot;);        &#125;        printf(&quot;
&quot;);    &#125;    // 计算总和、最大、最小    int sum = 0;    int max, min;    // 初始化最值    int firstIndex = 0;    int firstRow = firstIndex / COLS;    int firstCol = firstIndex % COLS;    max = arr[firstRow][firstCol];    min = arr[firstRow][firstCol];    for (int i = 0; i &lt; count; i++)    &#123;        int r = i / COLS;        int c = i % COLS;        int val = arr[r][c];        sum += val;        if (val &gt; max)            max = val;        if (val &lt; min)            min = val;    &#125;    printf(&quot;数组元素总和：%d
&quot;, sum);    printf(&quot;数组最大值：%d
&quot;, max);    printf(&quot;数组最小值：%d
&quot;, min);    return 0;&#125;
作业2：一维动态输入二维输出案例（增加继续输入功能）#include &lt;stdio.h&gt;#define MAX 6#define OVER -999int main()&#123;    int arr[MAX];    int count = 0;    char flag;    do    &#123;        // 录入数据        while (count &lt; MAX)        &#123;            printf(&quot;请输入第%d/%d个数(输入-999结束本轮录入)：&quot;, count + 1, MAX);            int num;            while (!scanf(&quot;%d&quot;, &amp;num))            &#123;                printf(&quot;输入有误，请重试:&quot;);                while (getchar() != &#x27;
&#x27;);            &#125;            if (num == OVER)                break;            arr[count++] = num;        &#125;        // 打印二维格式        printf(&quot;当前所有数据：
&quot;);        for (int i = 0; i &lt; MAX; i++)        &#123;            if (i &lt; count)                printf(&quot;%d &quot;, arr[i]);            else                printf(&quot;- &quot;);            if ((i + 1) % 3 == 0)                printf(&quot;
&quot;);        &#125;        if (count &gt;= MAX)        &#123;            printf(&quot;数组已满，无法继续输入！
&quot;);            break;        &#125;        getchar();        printf(&quot;是否继续输入数据？y/n：&quot;);        scanf(&quot;%c&quot;, &amp;flag);    &#125; while (flag == &#x27;y&#x27; || flag == &#x27;Y&#x27;);    printf(&quot;程序结束
&quot;);    return 0;&#125;
作业3：二维思路动态输入案例（拓展继续输入功能）#include &lt;stdio.h&gt;#define COWS 2#define COLS 3#define OVER -999int main()&#123;    int arr[COWS][COLS];    int count = 0;    char op;    do    &#123;        while (count &lt; COWS * COLS)        &#123;            printf(&quot;请输入第%d/%d个数(-999结束本轮)：&quot;, count + 1, COWS * COLS);            int num;            while (!scanf(&quot;%d&quot;, &amp;num))            &#123;                printf(&quot;输入有误，请重试:&quot;);                while (getchar() != &#x27;
&#x27;);            &#125;            if (num == OVER)                break;            int cow = count / COLS;            int col = count % COLS;            arr[cow][col] = num;            count++;        &#125;        // 打印二维数组        printf(&quot;现有数据：
&quot;);        for (int i = 0; i &lt; COWS; i++)        &#123;            for (int j = 0; j &lt; COLS; j++)            &#123;                if ((i * COLS + j) &lt; count)                    printf(&quot;%d &quot;, arr[i][j]);                else                    printf(&quot;- &quot;);            &#125;            printf(&quot;
&quot;);        &#125;        if (count &gt;= COWS * COLS)        &#123;            printf(&quot;数组空间已满，停止录入
&quot;);            break;        &#125;        getchar();        printf(&quot;是否继续录入剩余数据？y/n：&quot;);        scanf(&quot;%c&quot;, &amp;op);    &#125; while (op == &#x27;y&#x27; || op == &#x27;Y&#x27;);    return 0;&#125;
