一、数组基础文字讲解数组就是一堆相同类型数字/变量打包放在一块连续内存里，方便统一管理。

特点：全部元素类型一样、内存地址挨在一起、定义时必须写最大能存多少个；
下标：从0开始计数，第1个元素是arr[0]，第2个arr[1]，不能从1开始；
没手动赋值的数组，里面是随机乱码（垃圾值）；
代码里 int arr[10]：int代表存整数，arr是数组名字，[10]代表最多存10个数字。

配套完整代码#include &lt;stdio.h&gt;int main()&#123;    // 定义最多存10个整数的数组，未赋值，内部是垃圾值    int arr[10];    // 手动给前两个元素赋值    arr[0] = 10;    arr[1] = 20;    // 打印数组元素    printf(&quot;数组第1个元素 arr[0] = %d\n&quot;, arr[0]);    printf(&quot;数组第2个元素 arr[1] = %d\n&quot;, arr[1]);    // 打印每个元素的内存地址，证明地址连续    printf(&quot;查看内存地址：\n&quot;);    for(int i = 0; i &lt; 3; i++)    &#123;        printf(&quot;arr[%d] 的内存地址：%p\n&quot;, i, &amp;arr[i]);    &#125;    return 0;&#125;
二、数组三种初始化方式文字讲解初始化就是定义数组的时候直接给里面填数字，分3种写法：

完全初始化：大括号里数字数量 = 数组长度，全部位置都赋值；
省略长度初始化：中括号不写数字，电脑自动根据大括号里数字算出数组长度；
部分初始化：大括号数字比数组长度少，没写到的位置电脑自动填0；注意：只有定义数组那一行能批量赋值，分开写代码只能一个个元素单独赋值。

配套完整代码#include &lt;stdio.h&gt;int main()&#123;    // 1.完全初始化，数组长度5，5个数字全部赋值    int arr1[5] = &#123;1,2,3,4,5&#125;;    // 2.自动推导长度，电脑识别5个数字，数组长度=5    int arr2[] = &#123;1,2,3,4,5&#125;;    // 3.部分初始化，长度10，前5个赋值，后5个自动补0    int arr3[10] = &#123;1,2,3,4,5&#125;;    printf(&quot;完全初始化数组：&quot;);    for(int i = 0; i &lt; 5; i++)        printf(&quot;%d &quot;, arr1[i]);    printf(&quot;\n部分初始化数组（剩余自动补0）：&quot;);    for(int i = 0; i &lt; 10; i++)        printf(&quot;%d &quot;, arr3[i]);    return 0;&#125;
三、哨兵标记统计有效元素文字讲解有时候不知道数组里实际存了多少有效数字，可以设置一个特殊数字当“结束标记”（哨兵），比如-999；循环读取数组，读到这个特殊数字就停止，同时记录一共存了多少正常数字；用宏定义#define把结束数字单独写在最上面，方便以后修改。
配套完整代码#include &lt;stdio.h&gt;// 宏定义：数组最大容量#define MAX 10// 宏定义：哨兵结束标记，读到这个数代表数组结束#define OVER -999int main()&#123;    // 数组存5个有效数字，最后放哨兵标记    int arr[MAX] = &#123;1,2,3,4,5,OVER&#125;;    int i = 0;    printf(&quot;数组有效数字：&quot;);    // 没读到哨兵就持续循环    while (arr[i] != OVER)    &#123;        printf(&quot;%d &quot;,arr[i++]);    &#125;    // i最终等于有效数字个数    printf(&quot;\n数组一共有 %d 个有效元素&quot;,i);    return 0;&#125;
四、动态输入数组（两种输入方式）4.1 填满数组最大长度输入文字讲解循环让用户输入数字，直到把数组最大容量填满；增加输入校验：如果用户输入字母、符号，清空错误输入，重新让用户输入整数。
配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX];    int num;    // 循环填满整个数组    for (int i = 0; i &lt; MAX; i++)    &#123;        printf(&quot;请输入第%d/%d个整数：&quot;,i + 1,MAX);        // 判断输入是否不是数字        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入错误！请输入纯整数：&quot;);            // 清空缓冲区里错误字符            while (getchar() != &#x27;\n&#x27;);        &#125;        arr[i] = num;    &#125;    // 遍历输出全部输入内容    printf(&quot;你输入的所有数字：&quot;);    for (int i = 0; i &lt; MAX; i++)    &#123;        printf(&quot;%d &quot;,arr[i]);    &#125;    return 0;&#125;
4.2 输入-1提前结束录入文字讲解不用填满数组，输入-1就停止录入；用变量count记录真实有效数字数量，后续循环只读取count个数字，不会读取空位置。
配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX];    int count = 0; // 记录有效数字个数    // 数组没存满就持续输入    while (count &lt; MAX)    &#123;        printf(&quot;请输入第%d个数字（输入-1停止输入）：&quot;,count + 1);        int num;        // 校验输入是否为整数        while (!scanf(&quot;%d&quot;,&amp;num))        &#123;            printf(&quot;输入错误！请输入整数：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        // 输入-1直接退出循环        if (num == -1)            break;        arr[count++] = num;    &#125;    // 只打印有效数字    printf(&quot;你录入的有效数字：&quot;);    for (int i = 0; i &lt; count; i++)    &#123;        printf(&quot;%d &quot;,arr[i]);    &#125;    return 0;&#125;
五、数组增加元素（两种插入）5.1 指定位置插入数字文字讲解
先判断数组是否存满，满了不能插入；
用户看到的位置是从1开始，代码数组下标从0开始，需要减1转换；
插入位置后面所有数字全部往后挪一格，腾出空位，再放入新数字；
有效数字count +1。配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5; // 当前有效数字5个    int position, num;    // 判断数组是否已满    if (count &gt;= MAX)    &#123;        printf(&quot;数组存满了，无法插入！&quot;);        return 1;    &#125;    // 输入并校验插入位置    printf(&quot;请输入插入位置（从1开始计数）：&quot;);    while (1)    &#123;        while (!scanf(&quot;%d&quot;,&amp;position))        &#123;            printf(&quot;输入错误，请输入数字：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        // 位置范围校验        if (position &lt; 1 || position &gt; MAX)        &#123;            printf(&quot;位置无效，请重新输入：&quot;);            continue;        &#125;        break;    &#125;    // 输入要插入的数字    printf(&quot;请输入要插入的数字：&quot;);    while (!scanf(&quot;%d&quot;,&amp;num))    &#123;        printf(&quot;输入错误，请输入整数：&quot;);        while (getchar() != &#x27;\n&#x27;);    &#125;    // 插入逻辑    if (position &gt; count)    &#123;        // 插入到数组末尾        arr[count++] = num;    &#125;else    &#123;        // 数字全部后移一位        for (int i = count; i &gt;= position; i--)        &#123;            arr[i] = arr[i - 1];        &#125;        arr[position - 1] = num;        count++;    &#125;    // 输出插入后数组    printf(&quot;插入完成，当前数组：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;


5.2 找到指定数字，在它后面插入文字讲解
先遍历数组，查找用户输入的目标数字；
找不到目标数字直接提示退出；
找到后，该数字后面所有数字后移，腾出空位写入新数字；
有效数字count +1。配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5;    int findVal, insertNum, findIndex = -1;    if (count &gt;= MAX)    &#123;        printf(&quot;数组已满，不能插入！&quot;);        return 1;    &#125;    // 输入要查找的数字    printf(&quot;请输入要查找的数字：&quot;);    while (!scanf(&quot;%d&quot;,&amp;findVal))    &#123;        printf(&quot;输入错误，请输入整数：&quot;);        while (getchar() != &#x27;\n&#x27;);    &#125;    // 遍历数组找目标数字下标    for (int i = 0; i &lt; count; i++)    &#123;        if (arr[i] == findVal)        &#123;            findIndex = i;        &#125;    &#125;    // 下标-1代表没找到    if (findIndex == -1)    &#123;        printf(&quot;数组里没有这个数字！&quot;);        return 2;    &#125;    // 数字后移腾出空间    for (int i = count; i &gt; findIndex; i--)    &#123;        arr[i] = arr[i - 1];    &#125;    // 输入插入数字    printf(&quot;请输入要插入的新数字：&quot;);    while (!scanf(&quot;%d&quot;,&amp;insertNum))    &#123;        printf(&quot;输入错误，请输入整数：&quot;);        while (getchar() != &#x27;\n&#x27;);    &#125;    arr[findIndex] = insertNum;    count++;    printf(&quot;插入后数组：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;


六、数组删除元素（两种删除）6.1 指定位置删除文字讲解
校验输入位置合法（1~有效数字总数）；
删除位置后面所有数字全部往前挪一格，覆盖要删除的数字；
有效数字count -1。配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5;    int position;    printf(&quot;请输入要删除的位置（从1开始）：&quot;);    while (1)    &#123;        while (!scanf(&quot;%d&quot;,&amp;position))        &#123;            printf(&quot;输入错误，请输入数字：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        if (position &lt; 1 || position &gt; count)        &#123;            printf(&quot;位置无效，重新输入：&quot;);            continue;        &#125;        break;    &#125;    // 元素前移覆盖删除位置    for (int i = position; i &lt;= count; i++)    &#123;        arr[i - 1] = arr[i];    &#125;    count--;    printf(&quot;删除后数组：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;


6.2 指定数字删除文字讲解
遍历数组匹配用户输入数字，记录下标；
无匹配数字直接提示；
匹配到后，该数字后面所有元素前移覆盖；
有效数字count -1。配套完整代码#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5;    int delNum, findPos = -1;    printf(&quot;请输入要删除的数字：&quot;);    while (!scanf(&quot;%d&quot;,&amp;delNum))    &#123;        printf(&quot;输入错误，请输入整数：&quot;);        while (getchar() != &#x27;\n&#x27;);    &#125;    // 查找数字下标    for (int i = 0; i &lt; count; i++)    &#123;        if (arr[i] == delNum)        &#123;            findPos = i;        &#125;    &#125;    if (findPos == -1)    &#123;        printf(&quot;数组不存在该数字！&quot;);        return 2;    &#125;    // 元素前移覆盖    findPos += 1;    for (int i = findPos; i &lt;= count; i++)    &#123;        arr[i - 1] = arr[i];    &#125;    count--;    printf(&quot;删除后数组：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;


七、数组修改、查询7.1 指定位置修改元素文字讲解输入要修改的位置，校验位置合法，直接给对应下标赋值替换原有数字。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5;    int pos, newNum;    printf(&quot;输入要修改的位置（1开始）：&quot;);    scanf(&quot;%d&quot;, &amp;pos);    if(pos &lt; 1 || pos &gt; count)    &#123;        printf(&quot;位置不存在！&quot;);        return 0;    &#125;    printf(&quot;输入新数字：&quot;);    scanf(&quot;%d&quot;, &amp;newNum);    arr[pos - 1] = newNum;    printf(&quot;修改后数组：&quot;);    for(int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;, arr[i]);    return 0;&#125;
7.2 指定值查询元素文字讲解遍历数组，匹配目标数字，记录位置；循环结束无匹配提示查无此值。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[MAX] = &#123;1,2,3,4,5&#125;;    int count = 5;    int findNum, flag = 0;    printf(&quot;输入要查找的数字：&quot;);    scanf(&quot;%d&quot;, &amp;findNum);    for(int i = 0; i &lt; count; i++)    &#123;        if(arr[i] == findNum)        &#123;            printf(&quot;找到啦！数字在第 %d 位\n&quot;, i+1);            flag = 1;        &#125;    &#125;    if(flag == 0)        printf(&quot;数组里没有这个数字&quot;);    return 0;&#125;
八、数组求最大值、最小值、总和文字讲解
先把最大值、最小值、总和全部赋值为数组第一个数字；
从第二个数字开始循环对比：比max大就更新max，比min小就更新min，每个数字累加进sum。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[] = &#123;12,45,7,89,23&#125;;    int count = 5;    int max = arr[0];    int min = arr[0];    int sum = arr[0];    for (int i = 1; i &lt; count; i++)    &#123;        if (max &lt; arr[i])            max = arr[i];        if (min &gt; arr[i])            min = arr[i];        sum += arr[i];    &#125;    printf(&quot;最大值：%d\n最小值：%d\n所有数字总和：%d&quot;,max,min,sum);    return 0;&#125;


九、数组排序（选择排序+冒泡排序+优化冒泡）9.1 选择排序讲解外层循环控制每次要确定的最小数字位置；内层循环找到当前区间最小数字下标；最后交换两个下标数字。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[] = &#123;15,3,9,22,6&#125;;    int count = 5;    // 选择排序    for (int i = 0; i &lt; count - 1; i++)    &#123;        int min_index = i;        for (int j = i + 1; j &lt; count; j++)        &#123;            if(arr[min_index] &gt; arr[j])            &#123;                min_index = j;            &#125;        &#125;        if (min_index != i)        &#123;            int tmp = arr[i];            arr[i] = arr[min_index];            arr[min_index] = tmp;        &#125;    &#125;    printf(&quot;升序排序结果：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;
9.2 普通冒泡排序讲解相邻两个数字两两对比，前大后小就交换；每一轮循环结束，最大数字自动跑到末尾。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[] = &#123;15,3,9,22,6&#125;;    int count = 5;    for (int i = 0; i &lt; count - 1 ; i++)    &#123;        for (int j = 0; j &lt; count - 1 - i; j++)        &#123;            if (arr[j] &gt; arr[j + 1])            &#123;                int tmp = arr[j];                arr[j] = arr[j + 1];                arr[j + 1] = tmp;            &#125;        &#125;    &#125;    printf(&quot;冒泡排序结果：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;
9.3 优化冒泡排序讲解增加交换标记，如果一整轮循环没有交换任何数字，代表数组已经有序，直接结束循环，减少循环次数。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[] = &#123;15,3,9,22,6&#125;;    int count = 5;    for (int i = 0; i &lt; count - 1 ; i++)    &#123;        int is_swap = 1; // 标记：1代表本轮无交换        for (int j = 0; j &lt; count - 1 - i; j++)        &#123;            if (arr[j] &gt; arr[j + 1])            &#123;                int tmp = arr[j];                arr[j] = arr[j + 1];                arr[j + 1] = tmp;                is_swap = 0; // 发生交换，标记置0            &#125;        &#125;        if (is_swap)            break; // 无交换，直接退出排序    &#125;    printf(&quot;优化冒泡排序结果：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,arr[i]);    return 0;&#125;
十、数组拷贝文字讲解新建一个空数组，循环遍历原数组，把每个数字依次赋值给新数组，完成复制。#include &lt;stdio.h&gt;#define MAX 10int main()&#123;    int arr[] = &#123;1,2,3,4,5&#125;;    int count = 5;    int copy_arr[MAX];    // 循环拷贝    for (int i = 0; i &lt; count; i++)    &#123;        copy_arr[i] = arr[i];    &#125;    printf(&quot;拷贝后的数组：&quot;);    for (int i = 0; i &lt; count; i++)        printf(&quot;%d &quot;,copy_arr[i]);    return 0;&#125;
十一、字符数组与字符串文字讲解
普通字符数组：只存字母，没有\0结束标记，用%s打印会乱码越界；sizeof计算长度等于字符个数；
字符串写法char str[] = &quot;hello&quot;：电脑自动在末尾添加\0（字符串结束符），sizeof长度=字符数+1；
strlen()函数：只统计有效字母，不算\0，需要引入头文件&lt;string.h&gt;；
strcpy：直接复制整个字符串（包含末尾\0）；
strcmp：对比两个字符串，完全相同返回0。

完整代码#include &lt;stdio.h&gt;#include &lt;string.h&gt;int main()&#123;    // 普通字符数组，无\0    char str1[] = &#123;&#x27;h&#x27;,&#x27;e&#x27;,&#x27;l&#x27;,&#x27;l&#x27;,&#x27;o&#x27;&#125;;    // 字符串，自动带\0    char str2[] = &quot;hello&quot;;    char str3[100];    printf(&quot;str1占用字节：%zu\n&quot;, sizeof str1);    printf(&quot;str2占用字节：%zu\n&quot;, sizeof str2);    printf(&quot;str1有效字符长度：%zu\n&quot;, strlen(str1));    printf(&quot;str2有效字符长度：%zu\n&quot;, strlen(str2));    // 字符串拷贝两种方式    // 方式1：手动循环拷贝    for(int i = 0; i &lt; strlen(str2); i++)        str3[i] = str2[i];    str3[strlen(str2)] = &#x27;\0&#x27;;    printf(&quot;手动拷贝结果：%s\n&quot;, str3);    // 方式2：strcpy函数拷贝    char str4[100];    strcpy(str4, str2);    printf(&quot;strcpy拷贝结果：%s\n&quot;, str4);    // 字符串比较    char input[20];    printf(&quot;输入字符串对比hello：&quot;);    scanf(&quot;%s&quot;, input);    int res = strcmp(input, &quot;hello&quot;);    if(res == 0)        printf(&quot;两个字符串一模一样&quot;);    else if(res &gt; 0)        printf(&quot;你输入的字符串更大&quot;);    else        printf(&quot;你输入的字符串更小&quot;);    return 0;&#125;

MySQL 多表查询完整学习笔记
九、多表查询多表查询是指从多个表中检索相关数据的操作，通过关联多个表，可以获取比单个表更丰富、更完整的信息。
数据准备-- 创建部门表CREATE TABLE departments (    dept_id INT PRIMARY KEY,    dept_name VARCHAR(50) NOT NULL,    location VARCHAR(100));-- 创建员工表CREATE TABLE employees (    emp_id INT PRIMARY KEY,    name VARCHAR(50) NOT NULL,    dept_id INT,    salary DECIMAL(10,2),    manager_id INT,    FOREIGN KEY (dept_id) REFERENCES departments(dept_id));-- 创建项目表CREATE TABLE projects (    project_id INT PRIMARY KEY,    project_name VARCHAR(100),    dept_id INT,    budget DECIMAL(12,2),    FOREIGN KEY (dept_id) REFERENCES departments(dept_id));-- 插入部门数据INSERT INTO departments VALUES(1, &#x27;技术部&#x27;, &#x27;北京&#x27;),(2, &#x27;销售部&#x27;, &#x27;上海&#x27;),(3, &#x27;人事部&#x27;, &#x27;广州&#x27;),(4, &#x27;财务部&#x27;, &#x27;深圳&#x27;);-- 插入员工数据INSERT INTO employees VALUES(1, &#x27;张三&#x27;, 1, 8000, NULL),(2, &#x27;李四&#x27;, 1, 7500, 1),(3, &#x27;王五&#x27;, 2, 6000, NULL),(4, &#x27;赵六&#x27;, 2, 5500, 3),(5, &#x27;钱七&#x27;, 3, 5000, NULL),(6, &#x27;孙八&#x27;, NULL, 4500, NULL);-- 插入项目数据INSERT INTO projects VALUES(1, &#x27;网站开发&#x27;, 1, 50000),(2, &#x27;移动应用&#x27;, 1, 80000),(3, &#x27;市场推广&#x27;, 2, 30000),(4, &#x27;招聘系统&#x27;, 3, 20000);

1. INNER JOIN（内连接）返回两个表中匹配的记录，INNER 关键字可以省略。
-- 查询员工及其部门信息SELECT e.name, e.salary, d.dept_name, d.locationFROM employees eINNER JOIN departments d ON e.dept_id = d.dept_id;/* 通用语法SELECT 列名FROM 表1[INNER] JOIN 表2ON 表1.列 = 表2.列;*/-- 连接条件放在 ON 中，过滤条件放在 WHERE 中-- 查询参与项目的部门信息SELECT p.project_name, d.dept_name, p.budgetFROM projects pINNER JOIN departments d ON p.dept_id = d.dept_id;-- 多表内连接：员工-部门-项目SELECT e.name, d.dept_name, p.project_nameFROM employees eINNER JOIN departments d ON e.dept_id = d.dept_idINNER JOIN projects p ON d.dept_id = p.dept_id;

2. LEFT JOIN（左连接）返回左表所有记录和右表中匹配的记录，不匹配的部分用 NULL 填充。
-- 查询所有员工及其部门信息（包括没有部门的员工）SELECT e.name, e.salary, d.dept_nameFROM employees eLEFT JOIN departments d ON e.dept_id = d.dept_id;-- 查询所有部门及其员工（包括没有员工的部门）SELECT d.dept_name, e.nameFROM departments dLEFT JOIN employees e ON d.dept_id = e.dept_id;-- 查找没有部门的员工SELECT e.name, e.salaryFROM employees eLEFT JOIN departments d ON e.dept_id = d.dept_idWHERE d.dept_id IS NULL;

3. RIGHT JOIN（右连接）返回右表所有记录和左表中匹配的记录，不匹配的部分用 NULL 填充。
-- 查询所有部门及其员工（包括没有员工的部门）SELECT d.dept_name, e.nameFROM employees eRIGHT JOIN departments d ON e.dept_id = d.dept_id;-- 查找没有员工的部门SELECT d.dept_nameFROM employees eRIGHT JOIN departments d ON e.dept_id = d.dept_idWHERE e.emp_id IS NULL;

4. FULL JOIN（全连接）MySQL 不直接支持 FULL JOIN，可以用 UNION 模拟，返回左表和右表的所有记录，不匹配的部分用 NULL 填充。
-- 模拟全连接：返回所有员工和所有部门的组合SELECT e.name, d.dept_nameFROM employees eLEFT JOIN departments d ON e.dept_id = d.dept_idUNIONSELECT e.name, d.dept_nameFROM employees eRIGHT JOIN departments d ON e.dept_id = d.dept_id;

5. CROSS JOIN（交叉连接）返回两个表的笛卡尔积（所有行的组合），一般用于生成测试数据。
-- 员工和部门的笛卡尔积SELECT e.name, d.dept_nameFROM employees eCROSS JOIN departments d;-- 等价写法SELECT e.name, d.dept_nameFROM employees e, departments d;

6. SELF JOIN（自连接）表与自身进行连接，常用于查询层级关系（如员工-经理）。
-- 查询员工及其经理信息SELECT e1.name AS &#x27;员工&#x27;, e2.name AS &#x27;经理&#x27;FROM employees e1LEFT JOIN employees e2 ON e1.manager_id = e2.emp_id;-- 只显示有经理的员工SELECT e1.name AS &#x27;员工&#x27;, e2.name AS &#x27;领导&#x27;FROM employees e1LEFT JOIN employees e2 ON e1.manager_id = e2.emp_idWHERE e2.name IS NOT NULL;-- 示例：查询同一部门中，员工ID较小的员工对SELECT e1.name AS &#x27;员工1&#x27;, e2.name AS &#x27;员工2&#x27;, d.dept_nameFROM employees e1INNER JOIN employees e2 ON e1.dept_id = e2.dept_idINNER JOIN departments d ON e1.dept_id = d.dept_idWHERE e1.emp_id &lt; e2.emp_id;

MySQL 子查询完整学习笔记
八、子查询子查询（Subquery）是指嵌套在其他 SQL 查询中的查询语句，也被称为内部查询或嵌套查询，通常作为外部查询的条件或数据源。
1. 按位置分类
WHERE 子句中的子查询：作为过滤条件
FROM 子句中的子查询：作为派生表
SELECT 子句中的子查询：作为计算列


示例数据准备-- 员工表CREATE TABLE employees (    id INT PRIMARY KEY,    name VARCHAR(50),    department VARCHAR(50),    salary DECIMAL(10,2));-- 部门表CREATE TABLE departments (    dept_id INT PRIMARY KEY,    dept_name VARCHAR(50),    budget DECIMAL(12,2));-- 插入员工数据INSERT INTO employees VALUES(1, &#x27;张三&#x27;, &#x27;技术部&#x27;, 8000),(2, &#x27;李四&#x27;, &#x27;技术部&#x27;, 7500),(3, &#x27;王五&#x27;, &#x27;销售部&#x27;, 6000),(4, &#x27;赵六&#x27;, &#x27;销售部&#x27;, 5500),(5, &#x27;钱七&#x27;, &#x27;人事部&#x27;, 5000);-- 插入部门数据INSERT INTO departments VALUES(1, &#x27;技术部&#x27;, 100000),(2, &#x27;销售部&#x27;, 80000),(3, &#x27;人事部&#x27;, 60000);

1.1 WHERE 子句中的子查询（值或列）标量子查询（返回单个值）-- 查询工资高于平均工资的员工SELECT name, salaryFROM employeesWHERE salary &gt; (SELECT AVG(salary) FROM employees);-- 查询工资最高的员工信息SELECT name, salaryFROM employeesWHERE salary = (SELECT MAX(salary) FROM employees);
列子查询（返回一列数据）-- 查询在预算大于70000的部门工作的员工SELECT name, departmentFROM employeesWHERE department IN (    SELECT dept_name    FROM departments    WHERE budget &gt; 70000);-- 使用 NOT IN 查询不在预算小于70000部门工作的员工SELECT name, departmentFROM employeesWHERE department NOT IN (    SELECT dept_name    FROM departments    WHERE budget &lt; 70000);
使用 EXISTS 和 NOT EXISTS-- 查询有员工的部门信息SELECT dept_nameFROM departments dWHERE EXISTS (    SELECT 1    FROM employees e    WHERE e.department = d.dept_name);-- SELECT 1 FROM ... 是常见写法，&quot;1&quot; 是常量值，用于检查是否存在符合条件的行，不关心具体返回数据-- 查询没有员工的部门SELECT dept_nameFROM departments dWHERE NOT EXISTS (    SELECT 1    FROM employees e    WHERE e.department = d.dept_name);

1.2 FROM 子句中的子查询（派生表）-- 查询每个部门的平均工资（返回表），并筛选平均工资大于6000的部门SELECT dept_stats.department, dept_stats.avg_salaryFROM (    SELECT department, AVG(salary) as avg_salary    FROM employees    GROUP BY department) AS dept_statsWHERE dept_stats.avg_salary &gt; 6000;

SELECT ... FROM ... GROUP BY 是 SQL 分组聚合的核心组合，作用是按指定列分组后对每组进行聚合计算。

-- 查询工资排名前3的员工（返回表）SELECT name, salaryFROM (    SELECT name, salary    FROM employees    ORDER BY salary DESC    LIMIT 3) AS top_employees;

默认是升序（ASC），如果要降序，需要明确指定 DESC。


1.3 SELECT 子句中的子查询（返回标量/计算列）-- 查询每个员工的工资及其与平均工资的差值SELECT    name,    salary,    (SELECT AVG(salary) FROM employees) as avg_salary,    salary - (SELECT AVG(salary) FROM employees) as differenceFROM employees;-- 查询每个部门的人数SELECT    dept_name,    (SELECT COUNT(*) FROM employees WHERE department = d.dept_name) as employee_countFROM departments d;

2. 按返回值分类
标量子查询：返回单个值（一行一列）
列子查询：返回一列数据（多行一列）
行子查询：返回一行数据（一行多列）
表子查询：返回一个表（多行多列）

MySQL常见命令操作手册一、基础数据库、表操作命令1. 数据库操作-- 查看所有数据库show databases;-- 创建名为students数据库create database students;-- 进入/使用指定数据库use students;-- 查询当前所在数据库select database();-- 删除数据库drop database students;-- 查看数据库数据保存目录show variables like &quot;datadir&quot;;-- 查看数据库字符集show variables like &#x27;%char%&#x27;;-- 创建带特殊字符的数据库（反引号包裹名称）create database `student-new`;
2. 数据表基础操作-- 查看当前库所有表show tables;-- 创建t1表，id、name字段create table t1 (id varchar(20),name varchar(20));-- 查看表字段结构desc t1;-- 删除整张表drop table t1;-- 修改表名alter table class1 rename class01;-- 清空表内所有数据（保留表结构）delete from t1;
3. 表结构修改 alter table-- 修改字段长度alter table t1 modify column name varchar(20);-- 新增字段alter table students add address varchar(20) not null;-- 新增字段放在首位alter table class01 add uid int(20) first;-- 新增字段指定在某个字段后alter table class01 add address varchar(30) after age;-- 删除指定字段alter table students drop address;
4. 数据增删改查（DML基础）插入数据 insert-- 全字段插入单条数据insert into t1 values (&quot;1&quot;,&quot;mzj&quot;);-- 一次性插入多条数据insert into sunwukong values(1,&#x27;dasheng&#x27;,800,&#x27;jindouyun&#x27;),(2,&#x27;xingzhe&#x27;,800,&#x27;bianhua&#x27;),(3,&#x27;zhexing&#x27;,800,&#x27;jingubang&#x27;);
查询数据 select-- 查询表全部数据select * from t1;-- 查询指定字段select id from t1;select name,skill from sunwukong;-- 多条件筛选查询（字符串标准用单引号）select * from t1 where id=1 and name=&#x27;mzj&#x27;;-- NULL值判断不能用=，使用is null / is not null-- 跨库查询表数据select * from 数据库名.表名;
更新数据 update-- 根据条件修改指定字段update t1 set name=&#x27;lisi&#x27; where id=1;
删除数据 delete-- 删除整张表所有数据delete from t1;-- 根据条件删除单行数据delete from t1 where name=&#x27;zhangsan&#x27;;-- 删除空字符串数据delete from sunwukong where skill=&#x27;&#x27;;
5. 存储引擎相关命令-- 查看所有支持的存储引擎show engines;-- 查看当前默认存储引擎show variables like &#x27;%storage_engine%&#x27;;-- 修改指定表的存储引擎alter table t1 engine=innodb;

C语言赋值运算符、三元运算符、if分支结构全解前置作业作业2：将学生信息录入，并统计输出
（7）赋值运算符（双目运算符）分类
简单赋值运算符：=
复合赋值运算符：+=、-=、/=、%=

左值与右值概念
左值：拥有内存地址、可被赋值的内容，常见为变量
右值：可以放在赋值号右侧，包含常量、普通变量、函数返回值等

基础示例代码#include &lt;stdio.h&gt;int main()&#123;    int a = 10;    a += 5;  // a = a + 5    a -= 2;  // a = a - 2    a /= 3;  // a = a / 3    a %= 2;  // a = a % 2    printf(&quot;a = %d&quot;, a);    return 0;&#125;## （8）三元运算符（三目运算符）语法格式：`表达式1 ? 表达式2 : 表达式3`执行规则：1. 表达式1结果为真（非0），整体取值为表达式22. 表达式1结果为假（0），整体取值为表达式3### 示例1：两数取最大值```c#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 20;    int result = int_x &gt; int_y ? int_x : int_y;    printf(&quot;最大值：%d&quot;, result);    return 0;&#125;
示例2：三元运算符输出字符串#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 20;    printf(&quot;%d %s %d&quot;, int_x, int_x &gt; int_y ? &quot;大于&quot; : &quot;小于&quot;, int_y);    return 0;&#125;
三数求最大值两种写法思路1：先求前两数最大值，再和第三个数比较#include &lt;stdio.h&gt;int main()&#123;    int int_x = 50;    int int_y = 80;    int int_z = 30;    int result = (int_x &gt; int_y ? int_x : int_y) &gt; int_z     ? (int_x &gt; int_y ? int_x : int_y) : int_z;    printf(&quot;最大值：%d&quot;, result);    return 0;&#125;
思路2：嵌套三元运算符#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 40;    int int_z = 50;    int result = int_x &gt; int_y ? (int_x &gt; int_z ? int_x : int_z )     : (int_y &gt; int_z ? int_y : int_z );    printf(&quot;最大值：%d&quot;, result);    return 0;&#125;
作业3：输入三个数（支持整数/浮点数）输出最大值#include &lt;stdio.h&gt;int main()&#123;    float a, b, c, max;    printf(&quot;请输入三个数字，空格分隔：&quot;);    scanf(&quot;%f%f%f&quot;, &amp;a, &amp;b, &amp;c);    max = a &gt; b ? (a &gt; c ? a : c) : (b &gt; c ? b : c);    printf(&quot;三个数最大值为：%.2f&quot;, max);    return 0;&#125;
案例：输入5个整数，找出最大值思路：默认第一个数为最大值，后续数字依次对比更新最大值#include &lt;stdio.h&gt;int main()&#123;    int count = 1;    int num, max;    printf(&quot;请输入第%d个数：&quot;, count++);    scanf(&quot;%d&quot;, &amp;num);    max = num;    printf(&quot;请输入第%d个数：&quot;, count++);    scanf(&quot;%d&quot;, &amp;num);    max = max &gt; num ? max : num;    printf(&quot;请输入第%d个数：&quot;, count++);    scanf(&quot;%d&quot;, &amp;num);    max = max &gt; num ? max : num;    printf(&quot;请输入第%d个数：&quot;, count++);    scanf(&quot;%d&quot;, &amp;num);    max = max &gt; num ? max : num;    printf(&quot;请输入第%d个数：&quot;, count++);    scanf(&quot;%d&quot;, &amp;num);    max = max &gt; num ? max : num;    printf(&quot;最大值：%d&quot;, max);    return 0;&#125;
程序三大执行结构：顺序、分支（1）顺序执行代码从上至下依次执行，无跳转step1;step2;step3;
（2）分支执行：if语句形式1：单if分支（仅条件成立执行）语法：if (条件表达式)&#123;    执行语句;&#125;案例：两数求最大值#include &lt;stdio.h&gt;int main()&#123;    int int_x;    int int_y;    printf(&quot;请依次输入2个数：&quot;);    scanf(&quot;%d%d&quot;, &amp;int_x, &amp;int_y);    int max = int_x;    if (max &lt; int_y)    &#123;        max = int_y;    &#125;    printf(&quot;最大值：%d&quot;, max);    return 0;&#125;补充说明：scanf(&quot;%d&quot;) 读取数字时自动忽略空格、回车等空白字符
形式2：if-else 二分支语法：if (条件表达式)&#123;    执行语句1；&#125;else&#123;    执行语句2；&#125;案例：两数比较输出最大值#include &lt;stdio.h&gt;int main()&#123;    int int_x;    int int_y;    printf(&quot;请依次输入2个数：&quot;);    scanf(&quot;%d%d&quot;, &amp;int_x, &amp;int_y);    if (int_x &gt; int_y)    &#123;        printf(&quot;最大值：%d&quot;, int_x);    &#125;else    &#123;        printf(&quot;最大值：%d&quot;, int_y);     &#125;    return 0;&#125;
形式3：if-else if-else 多分支语法：if (条件表达式1)&#123;    执行语句1；&#125;else if (条件表达式2)&#123;    执行语句2；&#125;else&#123;    执行语句3；&#125;
案例1：简易数字选择计算器功能：输入1~4选择加减乘除#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;这是一个简易的计算器！\n&quot;    &quot;1:加法\n&quot;    &quot;2:减法\n&quot;    &quot;3:乘法\n&quot;    &quot;4:除法\n&quot;);    printf(&quot;请选择运算符：&quot;);    int operation;    scanf(&quot;%d&quot;, &amp;operation);    if (operation &lt; 1 || operation &gt; 4)    &#123;        printf(&quot;不支持的运算符！&quot;);        return 1;    &#125;    printf(&quot;请输入2个数：&quot;);    float num1;    float num2;    scanf(&quot;%f%f&quot;, &amp;num1, &amp;num2);    if (operation == 1)    &#123;        printf(&quot;%.2f + %.2f = %.2f&quot;, num1, num2, num1 + num2);    &#125;else if (operation == 2)    &#123;        printf(&quot;%.2f - %.2f = %.2f&quot;, num1, num2, num1 - num2);     &#125;else if (operation == 3)    &#123;        printf(&quot;%.2f * %.2f = %.2f&quot;, num1, num2, num1 * num2);     &#125;else    &#123;        if (num2 == 0)        &#123;            printf(&quot;除数不能为0！&quot;);            return 2;        &#125;        printf(&quot;%.2f / %.2f = %.2f&quot;, num1, num2, num1 / num2);     &#125;    return 0;&#125;
