C语言各类运算符完整解析文档一、算术运算符 +、-、*、/、%（双目操作符）基础示例代码#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    float float_y = 20.05;    printf(&quot;%d + %.2f = %.2f\n&quot;,int_x,float_y,int_x + float_y);    return 0;&#125;
类型隐式提升规则转换优先级：char → short → int → float → double运算时范围小的类型自动转为范围更大的类型参与计算。
除零UB（未定义行为）案例#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    float float_y = 0;    // 除数为0，触发UB不确定行为    printf(&quot;%d / %.2f = %.2f&quot;,int_x,float_y,int_x / float_y);    return 0;&#125;
UB行为后果：
运算结果随机不可预料
程序卡死、异常退出、崩溃
极端场景系统蓝屏

取模%限制说明%仅支持整型运算，浮点必须强制转换后取模：#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    float float_y = 20.05;    printf(&quot;%d %% %d = %d&quot;,int_x,(int)float_y,int_x % (int)float_y);    return 0;&#125;
二、关系运算符（双目运算符）运算符：&gt;、&gt;=、&lt;、&lt;=、!=、==
运算规则
运算结果只有两种：真1、假0
C语言判定规则：非0数值全部为真，0为假

作业需求：输入2个整数，实现全部算术运算#include &lt;stdio.h&gt;int main()&#123;    int a,b;    printf(&quot;请输入第一个整数：&quot;);    scanf(&quot;%d&quot;,&amp;a);    printf(&quot;请输入第二个整数：&quot;);    scanf(&quot;%d&quot;,&amp;b);    printf(&quot;%d + %d = %d\n&quot;,a,b,a+b);    printf(&quot;%d - %d = %d\n&quot;,a,b,a-b);    printf(&quot;%d * %d = %d\n&quot;,a,b,a*b);    if(b != 0)        printf(&quot;%d / %d = %.2f\n&quot;,a,b,(float)a/b);    else        printf(&quot;除数不能为0，无法做除法\n&quot;);    if(b != 0)        printf(&quot;%d %% %d = %d\n&quot;,a,b,a%b);    else        printf(&quot;除数不能为0，无法取模\n&quot;);    return 0;&#125;
三、自增自减运算符（单目运算符）++、—1. 前置自增/自减：先增减，再参与运算#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    printf(&quot;%d&quot;,++int_x + 10);    return 0;&#125;
同表达式多次自增UB示例#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = ++int_x + ++int_x + ++int_x;    // 同一变量连续多次前置自增，标准规定为UB未定义行为    printf(&quot;%d %d&quot;,int_x,int_y);    return 0;&#125;

注意：不允许在同一个表达式内对同一个变量多次使用++/--，结果随编译器不同而变化。

2. 后置自增/自减：先参与运算，运算结束后再增减#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = int_x-- + ++int_x + int_x--;    // 混合前后置自增且多次修改同一变量，同样属于UB    printf(&quot;%d %d&quot;,int_x,int_y);    return 0;&#125;
四、逻辑运算符运算符：&amp;&amp;（逻辑与）、||（逻辑或）、!（逻辑非，单目）
运算返回值结果只有：真1、假0
逻辑与 &amp;&amp; 真值表1 &amp;&amp; 1 → 11 &amp;&amp; 0 → 00 &amp;&amp; 1 → 00 &amp;&amp; 0 → 0
示例代码：#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 0;    printf(&quot;%d\n&quot;,int_x &amp;&amp; int_y);    printf(&quot;%d&quot;,!int_x &amp;&amp; !int_y);    return 0;&#125;
逻辑或 || 真值表1 || 1 → 11 || 0 → 10 || 1 → 10 || 0 → 0
示例代码：#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 20;    printf(&quot;%d&quot;,int_x || !int_y);    return 0;&#125;
短路特性（核心重点）
&amp;&amp;短路：左侧为假，右侧表达式完全不执行#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 0 &amp;&amp; int_x++;    // 0 &amp;&amp; 任意 直接判定假，int_x++不会执行    printf(&quot;%d %d&quot;,int_x,int_y);    return 0;&#125;
||短路：左侧为真，右侧表达式完全不执行#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = 1 || int_x++;    // 1 || 任意 直接判定真，int_x++不会执行    printf(&quot;%d %d&quot;,int_x,int_y);    return 0;&#125;


五、位运算符 &amp;、|、^、&gt;&gt;、&lt;&lt;1. 按位与 &amp;规则：同1为1，其余为01 &amp; 1 → 11 &amp; 0 → 00 &amp; 1 → 00 &amp; 0 → 0
2. 按位或 |规则：有1则1，全0才01 | 1 → 11 | 0 → 10 | 1 → 10 | 0 → 0示例：#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10; // 二进制 00001010    int int_y = 20; // 二进制 00010100    // 或运算结果 00011110    printf(&quot;%d&quot;,int_x | int_y);    return 0;&#125;
3. 按位异或 ^规则：相同为0，不同为11 ^ 1 → 00 ^ 0 → 01 ^ 0 → 10 ^ 1 → 1
4. 右移 &gt;&gt;、左移 &lt;&lt;数学结论：

变量 &lt;&lt; n 等价于 变量 × 2ⁿ
变量 &gt;&gt; n 等价于 变量 ÷ 2ⁿ（正数）

负数右移示例（补码运算）#include &lt;stdio.h&gt;int main()&#123;    int int_x = -10;    printf(&quot;%d&quot;,int_x &gt;&gt; 1);    return 0;&#125;
负数存储为补码，右移高位补符号位。
左移示例#include &lt;stdio.h&gt;int main()&#123;    char int_x = 30;    printf(&quot;%d\n&quot;,int_x &lt;&lt; 3);    printf(&quot;%d&quot;,int_x); // 移位不会改变原变量本身    return 0;&#125;
六、逗号运算符语法：(表达式1,表达式2,……,表达式n)执行逻辑：从左到右依次计算所有表达式，最终整个式子的值等于最后一个表达式的值
示例1#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    int int_y = (int_x++,int_x++,++int_x);    printf(&quot;%d %d&quot;,int_x,int_y);    return 0;&#125;
示例2#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    printf(&quot;%d&quot;,(int_x++,int_x++,int_x++));    return 0;&#125;
区分：函数参数逗号不是逗号运算符#include &lt;stdio.h&gt;int main()&#123;    int int_x = 10;    // printf参数内逗号是分隔符，不是逗号运算符    printf(&quot;%d %d %d&quot;,int_x++,int_x++,int_x++);    return 0;&#125;

