一、分支结构1.1 if-else 分支判断案例需求输入字符，y输出yes，n输出no，其他字符提示选择错误#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;请选择：&quot;);    char choice;    choice = getchar();    if (choice == &#x27;y&#x27;)    &#123;        printf(&quot;yes&quot;);    &#125;    else if (choice == &#x27;n&#x27;)    &#123;        printf(&quot;no&quot;);    &#125;    else    &#123;        printf(&quot;选择错误！&quot;);        return 1;    &#125;    return 0;&#125;
1.2 switch 多分支语句基础语法格式switch (表达式/变量)&#123;    case 常量1:        执行语句1;        break; // 跳出switch    case 常量2:        执行语句2;        break;    default: // 可选，匹配所有剩余情况        执行语句n;        break;&#125;
案例1：成绩分级（原始写法）需求：输入0~100分数，输出对应等级#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;请输入成绩：&quot;);    float score;    scanf(&quot;%f&quot;,&amp;score);    // 合法性校验    if (score &lt; 0 || score &gt; 100)    &#123;        printf(&quot;无效成绩！&quot;);        return 1;    &#125;    int level = score / 10;    switch (level)    &#123;        case 10:            printf(&quot;优秀！&quot;);            break;        case 9:            printf(&quot;优秀！&quot;);            break;        case 8:            printf(&quot;良好！&quot;);            break;        case 7:            printf(&quot;一般！&quot;);            break;        case 6:            printf(&quot;及格！&quot;);            break;        default:            printf(&quot;不及格！&quot;);            break;    &#125;    return 0;&#125;
案例2：成绩分级优化（多个case共用代码）多个case连续书写，可共用同一套输出逻辑，省略重复代码#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;请输入成绩：&quot;);    float score;    scanf(&quot;%f&quot;,&amp;score);    if (score &lt; 0 || score &gt; 100)    &#123;        printf(&quot;无效成绩！&quot;);        return 1;    &#125;    int level = score / 10;    switch (level)    &#123;        case 10: case 9:            printf(&quot;优秀！&quot;);            break;        case 8:            printf(&quot;良好！&quot;);            break;        case 7:            printf(&quot;一般！&quot;);            break;        case 6:            printf(&quot;及格！&quot;);            break;        default:            printf(&quot;不及格！&quot;);            break;    &#125;    return 0;&#125;

二、while 循环语句2.1 while 基础语法while (条件表达式)&#123;    循环体执行语句;&#125;
执行逻辑：

判断表达式，结果为真则执行循环体
执行完毕后再次判断条件
条件为假，直接退出循环

2.2 无限交替输出 1 0 1 0…#include &lt;stdio.h&gt;#include &lt;unistd.h&gt; // sleep函数依赖头文件int main()&#123;    int int_x = 0;    while (1) // 无限循环    &#123;        int_x ^= 1; // 异或1，0变1、1变0        printf(&quot;%d &quot;,int_x);        sleep(1); // 暂停1秒    &#125;    return 0;&#125;
2.3 计算1~100总和（两种结束写法）写法1：while条件直接限制范围#include &lt;stdio.h&gt;int main()&#123;    int int_x = 1;    int sum = 0;    while (int_x &lt;= 100)    &#123;        sum += int_x++;    &#125;    printf(&quot;1~100总和：%d&quot;,sum);    return 0;&#125;
写法2：while(1)无限循环 + break跳出#include &lt;stdio.h&gt;int main()&#123;    int int_x = 1;    int sum = 0;    while (1)    &#123;        sum += int_x++;        if (int_x &gt; 100)        &#123;            break; // 终止当前循环        &#125;    &#125;    printf(&quot;1~100总和：%d&quot;,sum);    return 0;&#125;
2.4 输入正整数，计算1到该数的总和核心知识点：continue 结束本次循环，直接进入下一轮判断#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;请输入整数：&quot;);    int num;    // 循环校验输入合法性    while (1)    &#123;        scanf(&quot;%d&quot;,&amp;num);        if (num &lt; 1)        &#123;            printf(&quot;请输入大于1的正整数:&quot;);            continue; // 跳过后续代码，重新输入        &#125;        break;    &#125;    int sum = 0;    int int_x = 1;    while (int_x &lt;= num)    &#123;        sum += int_x++;    &#125;    printf(&quot;1到%d的和：%d&quot;,num,sum);    return 0;&#125;
2.5 循环选择器：y继续 / n退出，其他提示错误知识点：while (getchar() != &#39;\n&#39;); 清空输入缓冲区，避免残留回车干扰下次输入#include &lt;stdio.h&gt;int main()&#123;    while (1)    &#123;        printf(&quot;请选，y继续，n结束：&quot;);        char choice;        scanf(&quot; %c&quot;,&amp;choice); // 空格吸收回车        if (choice == &#x27;y&#x27;)        &#123;            printf(&quot;选择正确！\n&quot;);            continue;        &#125;        else if (choice == &#x27;n&#x27;)        &#123;            printf(&quot;谢谢使用，bye~&quot;);            break;        &#125;        else        &#123;            printf(&quot;选择错误，请重新选择！\n&quot;);            while (getchar() != &#x27;\n&#x27;); // 清空缓冲区残留字符        &#125;    &#125;    return 0;&#125;
2.6 简易四则计算器综合案例整合 while循环 + switch分支 + 输入校验 + 循环选择退出#include &lt;stdio.h&gt;int main()&#123;    printf(&quot;这是一个简易的计算器！\n&quot;);    while (1)    &#123;        // 输入第一个数字        printf(&quot;请输入第一个数：&quot;);        float num1;        scanf(&quot;%f&quot;,&amp;num1);        // 输入并校验运算符        char operation;        while (1)        &#123;            printf(&quot;请输入操作符：&quot;);            scanf(&quot; %c&quot;,&amp;operation);            if (operation != &#x27;+&#x27; &amp;&amp; operation != &#x27;-&#x27;                &amp;&amp; operation != &#x27;*&#x27; &amp;&amp; operation != &#x27;/&#x27;)            &#123;                printf(&quot;不支持的操作符！\n&quot;);                while (getchar() != &#x27;\n&#x27;);                continue;            &#125;            break;        &#125;        // 输入第二个数字，校验除数不能为0        float num2;        while (1)        &#123;            printf(&quot;请输入第二个数：&quot;);            scanf(&quot;%f&quot;,&amp;num2);            if (operation == &#x27;/&#x27; &amp;&amp; num2 == 0)            &#123;                printf(&quot;除数不能为0,重新输入！\n&quot;);                continue;            &#125;            break;        &#125;        // 四则运算计算输出        switch (operation)        &#123;            case &#x27;+&#x27;:                printf(&quot;%.2f + %.2f = %.2f\n&quot;,num1,num2,num1 + num2);                break;            case &#x27;-&#x27;:                printf(&quot;%.2f - %.2f = %.2f\n&quot;,num1,num2,num1 - num2);                break;            case &#x27;*&#x27;:                printf(&quot;%.2f * %.2f = %.2f\n&quot;,num1,num2,num1 * num2);                break;            case &#x27;/&#x27;:                printf(&quot;%.2f / %.2f = %.2f\n&quot;,num1,num2,num1 / num2);                break;        &#125;        // 判断是否继续计算        while (1)        &#123;            printf(&quot;是否继续（y继续，n退出）：&quot;);            char choice;            scanf(&quot; %c&quot;,&amp;choice);            if (choice == &#x27;y&#x27;)            &#123;                break;            &#125;            else if (choice == &#x27;n&#x27;)            &#123;                printf(&quot;谢谢使用，bye!&quot;);                return 0;            &#125;            else            &#123;                printf(&quot;选择错误，请重新选择！\n&quot;);                while (getchar() != &#x27;\n&#x27;);            &#125;        &#125;    &#125;    return 0;&#125;

三、课堂作业案例3.1 输出100以内偶数（两种结束实现方式）方式1：步长为2，直接遍历偶数#include &lt;stdio.h&gt;int main()&#123;    int int_x = 0;    int count = 0;    while (int_x &lt;= 100)    &#123;        printf(&quot;%-3d&quot;,int_x);        // 每10个数字换行        if ((count + 1) % 10 == 0)        &#123;            printf(&quot;\n&quot;);        &#125;        count++;        int_x += 2;    &#125;    printf(&quot;\n共用%d个偶数。&quot;,count);    return 0;&#125;
方式2：逐个遍历数字，判断偶数，break终止循环#include &lt;stdio.h&gt;int main()&#123;    int int_x = 0;    int count = 0;    while (1)    &#123;        if (int_x % 2 == 0)        &#123;            printf(&quot;%-3d&quot;,int_x);            count++;            if ((count % 10 == 0))            &#123;                printf(&quot;\n&quot;);            &#125;        &#125;        int_x++;        if (int_x &gt; 100)        &#123;            break;        &#125;    &#125;    printf(&quot;\n共用%d个偶数！&quot;,count);    return 0;&#125;
拓展1：输入单个正整数，输出0~该数所有偶数#include &lt;stdio.h&gt;int main()&#123;    int num;    printf(&quot;请输入上限正整数：&quot;);    scanf(&quot;%d&quot;,&amp;num);    int int_x = 0;    int count = 0;    while (1)    &#123;        if (int_x % 2 == 0)        &#123;            printf(&quot;%-5d&quot;,int_x);            count++;            if ((count % 10 == 0))            &#123;                printf(&quot;\n&quot;);            &#125;        &#125;        int_x++;        if (int_x &gt; num)        &#123;            break;        &#125;    &#125;    printf(&quot;\n共用%d个偶数！&quot;,count);    return 0;&#125;
拓展2：输入区间上下限，输出区间内偶数（下限&lt;上限）#include &lt;stdio.h&gt;int main()&#123;    int num1;    // 输入下限    while (1)    &#123;        printf(&quot;请输入第一个数（下限）：&quot;);        scanf(&quot;%d&quot;,&amp;num1);        if (num1 &lt; 0)        &#123;            printf(&quot;输入错误，请输入正整数！\n&quot;);            continue;        &#125;        break;    &#125;    // 输入上限    int num2;    while (1)    &#123;        printf(&quot;请输入第二个数（上限）：&quot;);        scanf(&quot;%d&quot;,&amp;num2);        if (num2 &lt; num1)        &#123;            printf(&quot;第二个数应该比第一个数大！\n&quot;);            continue;        &#125;        break;    &#125;    int int_x = num1;    int count = 0;    while (1)    &#123;        if (int_x % 2 == 0)        &#123;            printf(&quot;%-5d&quot;,int_x);            count++;            if ((count % 10 == 0))            &#123;                printf(&quot;\n&quot;);            &#125;        &#125;        int_x++;        if (int_x &gt; num2)        &#123;            break;        &#125;    &#125;    printf(&quot;\n共用%d个偶数！&quot;,count);    return 0;&#125;
3.2 持续输入整数，输入-1结束程序功能：非法字符自动提示重新输入，清除缓冲区脏数据#include &lt;stdio.h&gt;int main()&#123;    int input_num;    while (1)    &#123;        printf(&quot;请输入数字：&quot;);        // 校验是否输入数字        while (!scanf(&quot;%d&quot;,&amp;input_num))        &#123;            printf(&quot;输入有误,请重新输入：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        if (input_num == -1)        &#123;            break;        &#125;        printf(&quot;%d\n&quot;,input_num);        while (getchar() != &#x27;\n&#x27;);    &#125;    return 0;&#125;

四、趣味综合案例4.1 猜数字游戏基础版：无次数限制#include &lt;stdio.h&gt;int main()&#123;    int target = 55; // 目标数字    int guest_num;    int count = 0;    printf(&quot;请输入数字：&quot;);    while (1)    &#123;        // 非法输入校验        while (!scanf(&quot;%d&quot;,&amp;guest_num))        &#123;            printf(&quot;输入有误，请重新输入：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        if (guest_num &gt; target)        &#123;            printf(&quot;猜大了，请重猜：&quot;);            count++;        &#125;        else if (guest_num &lt; target)        &#123;            printf(&quot;猜小了，请重猜：&quot;);            count++;        &#125;        else        &#123;            printf(&quot;恭喜，猜对了，共猜%d次&quot;,++count);            break;        &#125;    &#125;    return 0;&#125;
优化版：最多只能猜5次#include &lt;stdio.h&gt;int main()&#123;    int target = 55;    int guest_num;    int count = 0;    printf(&quot;请输入数字：&quot;);    while (1)    &#123;        while (!scanf(&quot;%d&quot;,&amp;guest_num))        &#123;            printf(&quot;输入有误，请重新输入：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        if (guest_num &gt; target)        &#123;            if (count &gt;= 4)            &#123;                printf(&quot;很遗憾，次数用完！&quot;);                break;            &#125;            printf(&quot;猜大了，请重猜：&quot;);            count++;        &#125;        else if (guest_num &lt; target)        &#123;            if (count &gt;= 4)            &#123;                printf(&quot;很遗憾，次数用完！&quot;);                break;            &#125;            printf(&quot;猜小了，请重猜：&quot;);            count++;        &#125;        else        &#123;            printf(&quot;恭喜，猜对了，共猜%d次&quot;,++count);            break;        &#125;    &#125;    return 0;&#125;
4.2 鸡兔同笼求解程序需求：输入总腿数，输出所有鸡、兔数量合法组合约束：腿数必须为正偶数#include &lt;stdio.h&gt;int main()&#123;    int leg_num;    printf(&quot;请输入腿数：&quot;);    // 输入合法性校验    while (1)    &#123;        while (!scanf(&quot;%d&quot;,&amp;leg_num))        &#123;            printf(&quot;输入有误，请输入数字：&quot;);            while (getchar() != &#x27;\n&#x27;);        &#125;        if (leg_num &lt; 0 || leg_num % 2 != 0)        &#123;            printf(&quot;输入有误，请重新输入：&quot;);            continue;        &#125;        break;    &#125;    int chicken = 0;    int count = 0;    printf(&quot;%-12s%-12s\n&quot;,&quot;鸡的个数&quot;,&quot;兔子的个数&quot;);    while (chicken * 2 &lt;= leg_num)    &#123;        // 剩余腿能被4整除，代表兔子数量合法        if ((leg_num - chicken * 2) % 4 == 0)        &#123;            printf(&quot;%-12d%-12d\n&quot;,chicken,(leg_num - chicken * 2) / 4);            count++;        &#125;        chicken++;    &#125;    printf(&quot;\n共有%d个组合。&quot;,count);    return 0;&#125;

五、课后作业：输入10个整数，输出最大值、最小值、总和需求分析
循环接收10个整数输入
实时记录最大值、最小值
累加所有数字求和
最终打印三项结果#include &lt;stdio.h&gt;int main()&#123;    int num, max, min, sum = 0;    int i = 1;    printf(&quot;请输入第%d个整数：&quot;,i);    scanf(&quot;%d&quot;,&amp;num);    max = min = num;    sum += num;    i++;    // 循环输入剩余9个数字    while (i &lt;= 10)    &#123;        printf(&quot;请输入第%d个整数：&quot;,i);        scanf(&quot;%d&quot;,&amp;num);        if (num &gt; max)            max = num;        if (num &lt; min)            min = num;        sum += num;        i++;    &#125;    printf(&quot;最大值：%d\n最小值：%d\n总和：%d&quot;,max,min,sum);    return 0;&#125;



附录：核心关键字总结
if-else：多条件分支判断
switch-case：等值多分支，搭配break跳出
while(条件)：先判断后执行循环
while(1)：无限循环，配合break终止循环
continue：结束当前单次循环，直接进入下一轮判断
getchar() 清空缓冲区：while (getchar() != &#39;\n&#39;); 解决输入残留回车干扰问题
